            //
            aOrbiterF = ((aOrbiterF + aOrbiterD) + 1272701355987972255U) + aNonceWordH;
            aOrbiterI = ((aOrbiterI ^ aOrbiterF) ^ 2341527290302413918U) ^ aNonceWordB;
            aOrbiterI = RotL64((aOrbiterI * 4259994329558538845U), 23U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterB) + 3572399386491321097U;
            aOrbiterD = ((aOrbiterD ^ aOrbiterH) ^ 9030543901860202313U) ^ aOrbiterUpdateSaltA[((aIndex + 5U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 15740041972946109029U), 29U);
