            aOrbiterC = (aWandererK + RotL64(aCross, 4U)) + 5608935247757980991U;
            aOrbiterJ = (aWandererC + RotL64(aPrevious, 27U)) + 8349890216627049501U;
            aOrbiterK = ((aWandererA + RotL64(aScatter, 21U)) + 14777509976829464381U) + aNonceWordM;
