            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 9574148731313441369U;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 15475837696410084246U;
            aOrbiterG = RotL64((aOrbiterG * 9483566889905630213U), 29U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterJ) + 10498923581670706837U) + aNonceWordC;
            aOrbiterI = ((aOrbiterI ^ aOrbiterA) ^ 16303603598939872725U) ^ aOrbiterUpdateSaltE[((aIndex + 18U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 6296566486106982897U), 37U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterI) + 8500926365869044669U;
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 10615693642705182289U;
            aOrbiterC = RotL64((aOrbiterC * 2390245401430786511U), 21U);
